import React, { useState } from "react";
import API from "../api";

const Login = () => {
  const [form, setForm] = useState({ email: "", password: "" });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await API.post("/api/auth/login", form);
      alert(res.data.message || "Login successful!");
    } catch (err) {
      alert(err.response?.data?.message || "Login failed!");
    }
  };

  return (
    <div className="flex justify-center items-center min-h-screen bg-gray-50">
      <form onSubmit={handleSubmit} className="bg-white shadow-lg rounded-xl p-8 w-96">
        <h2 className="text-2xl font-semibold text-center mb-6 text-green-600">Login</h2>

        <input
          type="email"
          placeholder="Email"
          className="border w-full p-3 mb-4 rounded-md"
          onChange={(e) => setForm({ ...form, email: e.target.value })}
        />

        <input
          type="password"
          placeholder="Password"
          className="border w-full p-3 mb-6 rounded-md"
          onChange={(e) => setForm({ ...form, password: e.target.value })}
        />

        <button
          type="submit"
          className="bg-green-600 w-full py-2 text-white rounded-lg hover:bg-green-700"
        >
          Login
        </button>
      </form>
    </div>
  );
};

export default Login;
